const products = $input.all().map((item) => item.json || {});
const input = $('Start').first().json.tool_input || {};

const EMPTY_RESULT = {
  sku: null,
  item_name: null,
  price: null,
  stock: 0,
  unit: null,
  category: null,
  is_active: null,
  resolved_quantity: 0,
  requested_quantity: Number(input.quantity || 0),
  requested_measure_unit: null,
  display_quantity_unit: 'pcs',
  requested_display: '',
  alternatives: [],
  can_fulfill: false,
  substitution_applied: false,
  substitution_reason: '',
  conversion_applied: false,
  resolver_reason: 'no_match',
};

const normalizeSpaces = (value) => String(value || '').replace(/\s+/g, ' ').trim();
const stripTrailingZeros = (value) => {
  const num = Number(value);
  if (!Number.isFinite(num)) return String(value || '0');
  return Number(num.toFixed(3)).toString();
};
const escapeRegex = (value) => String(value || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');

const UNIT_ALIASES = {
  kg: 'kg',
  kilo: 'kg',
  kilos: 'kg',
  kilogram: 'kg',
  kilograms: 'kg',
  g: 'g',
  gm: 'g',
  gram: 'g',
  grams: 'g',
  l: 'l',
  lt: 'l',
  ltr: 'l',
  litre: 'l',
  litres: 'l',
  liter: 'l',
  liters: 'l',
  ml: 'ml',
  millilitre: 'ml',
  millilitres: 'ml',
  milliliter: 'ml',
  milliliters: 'ml',
};

const TOKEN_ALIASES = {
  doodh: 'milk',
  dudh: 'milk',
  dudhh: 'milk',
  mlk: 'milk',
  paal: 'milk',
  pyaaz: 'onion',
  pyaz: 'onion',
  piyaz: 'onion',
  piyaj: 'onion',
  pyaaj: 'onion',
  onion: 'onion',
  onions: 'onion',
  aloo: 'potato',
  aaloo: 'potato',
  aalu: 'potato',
  tamatar: 'tomato',
  tamataro: 'tomato',
  dahi: 'curd',
  makhan: 'butter',
  namak: 'salt',
  cheeni: 'sugar',
  chawal: 'rice',
  atta: 'flour',
  tel: 'oil',
  chai: 'tea',
  haldi: 'turmeric',
  jeera: 'cumin',
  dhania: 'coriander',
};

const STOPWORDS = new Set([
  'add', 'need', 'want', 'please', 'pls', 'give', 'send', 'deliver', 'delivering',
  'checkout', 'place', 'order', 'my', 'address', 'home', 'office', 'to', 'at', 'for',
  'and', 'with', 'of', 'the', 'a', 'an', 'more', 'another', 'set', 'make', 'change',
  'fresh', 'new', 'usual', 'same', 'item', 'items', 'piece', 'pieces', 'pc', 'pcs',
  'packet', 'packets', 'pack', 'packs', 'road', 'rd', 'street', 'st', 'lane', 'ln',
  'block', 'sector', 'nagar', 'city', 'flat', 'apartment', 'apt', 'bengaluru', 'bangalore',
]);

const MEASURE_WORDS = new Set(Object.keys(UNIT_ALIASES));
const ADDRESS_WORDS = /\b(road|rd|street|st|lane|ln|sector|block|nagar|city|flat|apartment|apt|bengaluru|bangalore|mumbai|delhi|hyderabad|pune|chennai|kolkata)\b/i;

const normalizeUnit = (value) => UNIT_ALIASES[String(value || '').toLowerCase().trim()] || null;
const unitKind = (unit) => (unit === 'kg' || unit === 'g') ? 'weight' : (unit === 'l' || unit === 'ml') ? 'volume' : 'count';
const toBaseUnits = (amount, unit) => {
  const normalizedUnit = normalizeUnit(unit) || unit;
  const numeric = Number(amount);
  if (!Number.isFinite(numeric)) return null;
  if (normalizedUnit === 'kg') return numeric * 1000;
  if (normalizedUnit === 'g') return numeric;
  if (normalizedUnit === 'l') return numeric * 1000;
  if (normalizedUnit === 'ml') return numeric;
  return null;
};
const singularize = (token) => {
  if (!token) return token;
  if (token.endsWith('ies') && token.length > 3) return `${token.slice(0, -3)}y`;
  if (token.endsWith('oes') && token.length > 3) return token.slice(0, -2);
  if (token.endsWith('ses') && token.length > 3) return token.slice(0, -2);
  if (token.endsWith('s') && token.length > 3 && !token.endsWith('ss')) return token.slice(0, -1);
  return token;
};

const safeLower = (value) => normalizeSpaces(String(value || '').normalize('NFKC').toLowerCase());
const cleanText = (value) => safeLower(value).replace(/[^\p{L}\p{N}\s.&-]+/gu, ' ');
const normalizeToken = (token) => {
  const cleaned = cleanText(token).replace(/[.&-]+/g, ' ').trim();
  if (!cleaned) return '';
  const raw = TOKEN_ALIASES[cleaned] || singularize(cleaned);
  return TOKEN_ALIASES[raw] || raw;
};

const extractInlineMeasure = (value) => {
  const text = cleanText(value);
  const match = text.match(/(\d+(?:\.\d+)?)\s*(kg|kilo|kilos|kilogram|kilograms|g|gm|gram|grams|ml|l|lt|ltr|litre|litres|liter|liters|millilitre|millilitres|milliliter|milliliters)\b/i);
  if (!match) return null;
  return {
    amount: Number(match[1]),
    unit: normalizeUnit(match[2]),
    text: match[0],
  };
};

const tokenize = (value) => {
  const text = cleanText(value)
    .replace(/\d+(?:\.\d+)?/g, ' ')
    .replace(/[.&-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  if (!text) return [];

  return text
    .split(' ')
    .map((token) => normalizeToken(token))
    .filter((token) => token && token.length > 1 && !STOPWORDS.has(token) && !MEASURE_WORDS.has(token));
};

const diceCoefficient = (a, b) => {
  const left = String(a || '');
  const right = String(b || '');
  if (!left || !right) return 0;
  if (left === right) return 1;
  if (left.length < 2 || right.length < 2) return 0;
  const pairs = (value) => {
    const out = [];
    for (let index = 0; index < value.length - 1; index += 1) {
      out.push(value.slice(index, index + 2));
    }
    return out;
  };
  const leftPairs = pairs(left);
  const rightPairs = pairs(right);
  const rightCount = new Map();
  for (const pair of rightPairs) {
    rightCount.set(pair, (rightCount.get(pair) || 0) + 1);
  }
  let overlap = 0;
  for (const pair of leftPairs) {
    const count = rightCount.get(pair) || 0;
    if (count > 0) {
      overlap += 1;
      rightCount.set(pair, count - 1);
    }
  }
  return (2 * overlap) / (leftPairs.length + rightPairs.length);
};

const parsePackInfo = (itemName, itemUnit) => {
  const rawName = String(itemName || '');
  const lower = safeLower(rawName);
  const measureMatch = lower.match(/(\d+(?:\.\d+)?)\s*(kg|kilo|kilos|kilogram|kilograms|g|gm|gram|grams|ml|l|lt|ltr|litre|litres|liter|liters|millilitre|millilitres|milliliter|milliliters)\b/i);
  if (measureMatch) {
    return {
      amount: Number(measureMatch[1]),
      unit: normalizeUnit(measureMatch[2]),
      source: 'name',
    };
  }

  const unit = normalizeUnit(itemUnit);
  if (unit && unitKind(unit) !== 'count') {
    return {
      amount: 1,
      unit,
      source: 'unit',
    };
  }

  const loose = /\bloose\b/.test(lower);
  if (loose && unit && unitKind(unit) !== 'count') {
    return {
      amount: 1,
      unit,
      source: 'loose',
    };
  }

  return null;
};

const buildQueryInfo = () => {
  const rawQuery = normalizeSpaces(String(input.product_name || ''));
  const inlineMeasure = extractInlineMeasure(rawQuery);
  const explicitUnit = normalizeUnit(input.requested_measure_unit);
  const requestedUnit = explicitUnit || (inlineMeasure ? inlineMeasure.unit : null);
  const requestedQuantity = Number(input.quantity ?? (inlineMeasure ? inlineMeasure.amount : 1));
  const cleanedQuery = normalizeSpaces(
    inlineMeasure ? rawQuery.replace(new RegExp(escapeRegex(inlineMeasure.text), 'i'), ' ') : rawQuery,
  );
  const tokens = tokenize(cleanedQuery);
  const canonical = tokens.join(' ');
  const requestedDisplay = requestedUnit
    ? `${stripTrailingZeros(requestedQuantity)}${requestedUnit}`
    : stripTrailingZeros(requestedQuantity);

  return {
    rawQuery,
    cleanedQuery,
    tokens,
    canonical,
    requestedQuantity,
    requestedUnit,
    requestedDisplay,
  };
};

const query = buildQueryInfo();
if (!query.cleanedQuery) {
  return [{ json: EMPTY_RESULT }];
}

const fuzzyTokenMatch = (token, candidateTokens) => {
  for (const candidate of candidateTokens) {
    if (!candidate) continue;
    if (candidate === token) return true;
    if (candidate.includes(token) || token.includes(candidate)) return true;
    if (diceCoefficient(candidate, token) >= 0.72) return true;
  }
  return false;
};

const buildCandidate = (product) => {
  const itemName = String(product.item_name || '');
  const candidateTokens = tokenize(itemName);
  const candidateCanonical = candidateTokens.join(' ');
  const stock = Number(product.stock || 0);
  const isActive = product.is_active === true;
  const packInfo = parsePackInfo(itemName, product.unit);

  let overlap = 0;
  for (const token of query.tokens) {
    if (fuzzyTokenMatch(token, candidateTokens)) overlap += 1;
  }
  const overlapRatio = query.tokens.length ? overlap / query.tokens.length : 0;
  const diceScore = diceCoefficient(query.canonical, candidateCanonical || safeLower(itemName));
  const containsAllTokens = query.tokens.length > 0 && overlap === query.tokens.length;

  let textScore = overlapRatio * 100 + diceScore * 35;
  if (candidateCanonical && candidateCanonical === query.canonical) textScore += 70;
  if (candidateCanonical && query.canonical && (candidateCanonical.startsWith(query.canonical) || query.canonical.startsWith(candidateCanonical))) textScore += 28;
  if (containsAllTokens) textScore += 25;

  const requestedUnit = query.requestedUnit;
  let resolvedQuantity = Number(query.requestedQuantity || 0);
  let compatibleMeasure = !requestedUnit;
  let conversionApplied = false;
  let fractionalPack = false;
  let packaged = /\b(pack|pkt|bottle|box|pouch|loaf|tetra|carton|dozen|biscuits|soap|shampoo|tea|coffee|bread|milk)\b/i.test(itemName) || String(product.unit || '').toLowerCase() === 'pcs';

  if (requestedUnit) {
    const requestBase = toBaseUnits(query.requestedQuantity, requestedUnit);
    if (packInfo && unitKind(packInfo.unit) === unitKind(requestedUnit)) {
      const packBase = toBaseUnits(packInfo.amount, packInfo.unit);
      compatibleMeasure = Number.isFinite(requestBase) && Number.isFinite(packBase) && packBase > 0;
      if (compatibleMeasure) {
        resolvedQuantity = requestBase / packBase;
        if (packaged) {
          if (Math.abs(resolvedQuantity - Math.round(resolvedQuantity)) < 1e-9) {
            resolvedQuantity = Math.round(resolvedQuantity);
          } else {
            fractionalPack = true;
            resolvedQuantity = Number(resolvedQuantity.toFixed(3));
          }
        } else {
          resolvedQuantity = Number(resolvedQuantity.toFixed(3));
        }
        conversionApplied = true;
      }
    } else {
      const productUnit = normalizeUnit(product.unit);
      if (productUnit && unitKind(productUnit) === unitKind(requestedUnit)) {
        compatibleMeasure = true;
        resolvedQuantity = Number(query.requestedQuantity);
        conversionApplied = false;
      } else {
        compatibleMeasure = false;
      }
    }
  }

  if (!Number.isFinite(resolvedQuantity) || resolvedQuantity <= 0) {
    resolvedQuantity = Number(query.requestedQuantity || 0);
  }

  const canFulfill = compatibleMeasure && resolvedQuantity > 0 && resolvedQuantity <= stock + 1e-9 && !(fractionalPack && packaged);

  const availabilityTier = canFulfill && isActive
    ? 0
    : canFulfill
      ? 1
      : stock > 0 && isActive
        ? 2
        : stock > 0
          ? 3
          : 4;

  let finalScore = textScore;
  if (compatibleMeasure) finalScore += 18;
  else if (requestedUnit) finalScore -= 20;
  if (isActive) finalScore += 12;
  else finalScore -= 18;
  if (stock > 0) finalScore += Math.min(stock, 12);
  else finalScore -= 18;
  if (canFulfill) finalScore += 32;
  if (fractionalPack) finalScore -= 24;

  const displayQuantityUnit = (() => {
    const lowerName = safeLower(itemName);
    if (requestedUnit && /\bloose\b/.test(lowerName)) return requestedUnit;
    if (packInfo && unitKind(packInfo.unit) !== 'count' && !/\bloose\b/.test(lowerName) && String(product.unit || '').toLowerCase() !== 'pcs') {
      return resolvedQuantity === 1 ? 'pack' : 'packs';
    }
    return String(product.unit || 'pcs').toLowerCase() || 'pcs';
  })();

  return {
    product,
    itemName,
    stock,
    isActive,
    candidateCanonical,
    textScore,
    finalScore,
    overlapRatio,
    diceScore,
    containsAllTokens,
    packInfo,
    compatibleMeasure,
    resolvedQuantity,
    canFulfill,
    conversionApplied,
    fractionalPack,
    packaged,
    availabilityTier,
    displayQuantityUnit,
  };
};

const candidates = products.map(buildCandidate);
const viable = candidates.filter((candidate) => candidate.textScore >= 48 || candidate.overlapRatio >= 0.55 || candidate.diceScore >= 0.52);
const suggestionPool = [...candidates]
  .filter((candidate) => candidate.textScore >= 28 || candidate.overlapRatio >= 0.35 || candidate.diceScore >= 0.35)
  .sort((left, right) => right.textScore - left.textScore || right.stock - left.stock || left.itemName.localeCompare(right.itemName));

if (viable.length === 0) {
  return [{
    json: {
      ...EMPTY_RESULT,
      requested_quantity: query.requestedQuantity,
      requested_measure_unit: query.requestedUnit,
      requested_display: query.requestedDisplay,
      alternatives: suggestionPool.slice(0, 3).map((candidate) => ({
        item_name: candidate.itemName,
        stock: candidate.stock,
        price: Number(candidate.product.price || 0),
      })),
    },
  }];
}

const lexicalTop = [...viable].sort((left, right) => right.textScore - left.textScore || left.availabilityTier - right.availabilityTier || right.stock - left.stock)[0];
const ranked = [...viable].sort((left, right) => {
  if (left.availabilityTier !== right.availabilityTier) return left.availabilityTier - right.availabilityTier;
  if (Math.abs(left.finalScore - right.finalScore) > 1e-9) return right.finalScore - left.finalScore;
  if (left.fractionalPack !== right.fractionalPack) return left.fractionalPack ? 1 : -1;
  if (left.stock !== right.stock) return right.stock - left.stock;
  if (Number(left.product.price || 0) !== Number(right.product.price || 0)) return Number(left.product.price || 0) - Number(right.product.price || 0);
  return left.itemName.localeCompare(right.itemName);
});

const best = ranked[0];
const substitutionApplied = Boolean(lexicalTop && lexicalTop.product.sku !== best.product.sku);
let substitutionReason = '';
if (substitutionApplied && lexicalTop) {
  if (Number(lexicalTop.stock || 0) <= 0 || lexicalTop.isActive !== true) {
    substitutionReason = `Used ${best.itemName} because ${lexicalTop.itemName} is unavailable right now.`;
  } else {
    substitutionReason = `Used ${best.itemName} because it is the closest match I can fulfil right now.`;
  }
}

return [{
  json: {
    sku: best.product.sku,
    item_name: best.itemName,
    price: best.product.price,
    stock: best.stock,
    unit: best.product.unit,
    category: best.product.category,
    is_active: best.product.is_active,
    resolved_quantity: Number(best.resolvedQuantity),
    requested_quantity: Number(query.requestedQuantity),
    requested_measure_unit: query.requestedUnit,
    display_quantity_unit: best.displayQuantityUnit,
    requested_display: query.requestedDisplay,
    can_fulfill: best.canFulfill,
    substitution_applied: substitutionApplied,
    substitution_reason: substitutionReason,
    conversion_applied: Boolean(query.requestedUnit && best.compatibleMeasure),
    resolver_reason: best.canFulfill ? 'matched_in_stock' : best.stock > 0 ? 'insufficient_stock' : 'matched_out_of_stock',
    alternatives: ranked.slice(1, 4).map((candidate) => ({
      item_name: candidate.itemName,
      stock: candidate.stock,
      price: Number(candidate.product.price || 0),
    })),
  },
}];

const input = $('Start').first().json.tool_input || {};
const match = $('Find Best Match').first().json || {};
const alternatives = Array.isArray(match.alternatives) ? match.alternatives : [];

let message = `Sorry, I could not find "${input.product_name}" in our store.`;
if (alternatives.length > 0) {
  const suggestions = alternatives
    .map((item) => `${item.item_name}${Number(item.stock || 0) > 0 ? '' : ' (out of stock)'}`)
    .join(', ');
  message += ` Closest matches: ${suggestions}.`;
}
message += ' Try a different name or add a brand/size.';

return [{
  json: {
    confirmation_message: message,
    chat_id: input.chat_id,
  },
}];

