const input = $('Start').first().json.tool_input;
const product = $('Find Best Match').first().json;
const runningTotal = Number($('Get Cart Total After Remove').first().json.running_total || 0);

const unit = product.unit ? ' ' + product.unit : '';
let msg = 'Removed from cart\n\n• ' + product.item_name + ' from your cart.';
msg += '\n\nCart total: ₹' + runningTotal.toFixed(0);

return [{ json: { confirmation_message: msg, chat_id: input.chat_id } }];

const input = $('Start').first().json.tool_input || {};
const match = $('Find Best Match').first().json || {};
const alternatives = Array.isArray(match.alternatives) ? match.alternatives : [];
const requestedUnit = String(match.requested_measure_unit || '').trim();
const requestedQty = Number(match.requested_quantity || input.quantity || 0);
const stock = Number(match.stock || 0);
const availableLabel = requestedUnit && stock > 0
  ? `${stock} ${requestedUnit}`
  : `${stock} ${stock === 1 ? 'unit' : 'units'}`;

let message;
if (stock > 0) {
  message = `Sorry, I can only fulfil up to ${availableLabel} of ${match.item_name || input.product_name} right now.`;
} else {
  message = `Sorry, ${match.item_name || input.product_name} is currently out of stock.`;
}

if (requestedUnit && requestedQty > 0) {
  message += ` You asked for ${requestedQty}${requestedUnit}.`;
}

if (alternatives.length > 0) {
  const suggestionText = alternatives
    .map((item) => `${item.item_name}${Number(item.stock || 0) > 0 ? '' : ' (out of stock)'}`)
    .join(', ');
  message += ` Closest available options: ${suggestionText}.`;
}

message += ' Send another item or try a different size.';

return [{
  json: {
    confirmation_message: message,
    chat_id: input.chat_id,
  },
}];

parameters.query:
=-- Expire stale carts (>6 hours inactive)
UPDATE public.carts
SET status = 'expired'
WHERE user_id = {{ $('Start').first().json.tool_input.chat_id }}
  AND status = 'active'
  AND COALESCE(last_activity_at, created_at) < NOW() - INTERVAL '6 hours';

-- Create new active cart if none exists
INSERT INTO public.carts (user_id, store_id, status, last_activity_at)
SELECT {{ $('Start').first().json.tool_input.chat_id }}, 1, 'active', NOW()
WHERE NOT EXISTS (
  SELECT 1 FROM public.carts
  WHERE user_id = {{ $('Start').first().json.tool_input.chat_id }} AND status = 'active'
);

-- Touch last_activity_at
UPDATE public.carts SET last_activity_at = NOW()
WHERE user_id = {{ $('Start').first().json.tool_input.chat_id }} AND status = 'active';

-- Return cart_id
SELECT cart_id FROM public.carts
WHERE user_id = {{ $('Start').first().json.tool_input.chat_id }} AND status = 'active'
LIMIT 1;

=SELECT ci.sku, ci.quantity, ci.price_at_addition 
FROM public.cart_items ci 
JOIN public.carts c ON ci.cart_id = c.cart_id 
WHERE c.user_id = {{ $('Start').first().json.tool_input.chat_id }} 
AND c.status = 'active';

