const input = $('Start').first().json.tool_input;
const product = $('Find Best Match').first().json;

const cartItems = $('Get Cart Items After Add')
  .all()
  .map((entry) => entry.json)
  .filter((entry) => entry && entry.sku);

let runningTotal = 0;
for (const entry of cartItems) {
  runningTotal += parseFloat(entry.quantity) * parseFloat(entry.price_at_addition);
}

const payload = {
  runningTotal,
  chat_id: input.chat_id,
  sku: product.sku,
  cart_total: runningTotal,
};

return [
  {
    json: payload,
  },
];

const input = $('Start').first().json.tool_input;
const product = $('Find Best Match').first().json;
const qty = parseFloat(input.quantity);
const price = parseFloat(product.price);
const lineTotal = (qty * price).toFixed(0);
const unit = product.unit ? ' ' + product.unit : '';
const runningTotal = $('Build Cart Total').first().json.runningTotal;
const mode = (input.mode || 'add').toLowerCase();
const remainingStock = Number(product.stock) - qty;
let stockWarn = '';
if (remainingStock > 0 && remainingStock <= 3) {
  stockWarn = '\n\n⚠️ Only ' + remainingStock + ' ' + (product.unit || 'units') + ' of ' + product.item_name + ' left!';
}
let bodyText;
if (mode === 'remove') {
  bodyText = 'Removed from cart\n\n• ' + product.item_name + ' × ' + qty + unit + stockWarn;
} else {
  bodyText = '✅ Added to cart\n\n• ' + product.item_name + ' × ' + qty + unit + ' — ₹' + lineTotal + stockWarn;
}
bodyText += '\n\nCart total: ₹' + runningTotal.toFixed(0);
return [{ json: {
  confirmation_message: bodyText,
  chat_id: input.chat_id,
  customer_ui_state: 'CART_ACTIVE',
  message_type: 'button',
  body_text: bodyText,
  buttons: [
    { id: 'view_cart', title: '🛒 View Cart' },
    { id: 'checkout', title: '✓ Checkout' },
  ],
} }];

