const price = parseFloat(product.price);
const lineTotal = (qty * price).toFixed(0);
const unit = product.unit ? ' ' + product.unit : '';
const runningTotal = $('Build Cart Total').first().json.runningTotal;
const mode = (input.mode || 'add').toLowerCase();
const remainingStock = Number(product.stock) - qty;
